import{_ as r,c as o,o as a,ag as n}from"./chunks/framework.XjE0kKti.js";const s="/gatewayweb/docs/assets/hub0081-template-list.DjEpXuvc.png",d="/gatewayweb/docs/assets/hub0081-template-menu.BSLSsWXU.png",e="/gatewayweb/docs/assets/hub0081-template-edit-content.C2k5DsuZ.png",m=JSON.parse('{"title":"预警模板管理（hub0081）","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0081.md","filePath":"modules/hub0081.md","lastUpdated":1776841524000}'),g={name:"modules/hub0081.md"};function h(l,t,b,i,c,u){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="预警模板管理-hub0081" tabindex="-1">预警模板管理（hub0081） <a class="header-anchor" href="#预警模板管理-hub0081" aria-label="Permalink to &quot;预警模板管理（hub0081）&quot;">​</a></h1><p>维护告警消息的 <strong>标题模板</strong> 与 <strong>内容模板</strong>，使用与后端一致的 <strong>Mustache</strong> 占位符语法（双花括号包裹字段路径，例如 <span>{{title}}</span>、<span>{{content}}</span>），发送时由后端替换为实际标题、正文、时间、标签、表格字段等。模板按 <strong>模板名称</strong> 唯一标识，并绑定 <strong>渠道类型</strong>（或通用）、<strong>显示格式</strong> 与启用状态，供 <strong><a href="./hub0080.html">预警服务配置（hub0080）</a></strong> 中「默认模板名称」引用。</p><p><img src="'+s+'" alt="模板列表与筛选"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>模板 CRUD</td><td><strong>新增 / 编辑 / 查看</strong> 使用弹窗（三 Tab）；<strong>删除</strong> 支持右键单行或工具栏勾选批量删除。</td></tr><tr><td>启停</td><td>列表「启用状态」列 <strong>开关</strong> 直接切换，通过更新模板接口写回。</td></tr><tr><td>渠道与格式</td><td>渠道类型可为具体渠道或「通用」；显示格式为 <strong>文本</strong> 或 <strong>表格</strong>。</td></tr><tr><td>邮件内容</td><td>渠道类型为 <strong>邮件</strong> 时，「内容模板」使用 <strong>富文本</strong> 编辑，输出 HTML；其它渠道为 Markdown 代码编辑。</td></tr></tbody></table><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>预警管理</strong> → <strong>预警模板管理</strong>。</p><hr><h2 id="列表与筛选" tabindex="-1">列表与筛选 <a class="header-anchor" href="#列表与筛选" aria-label="Permalink to &quot;列表与筛选&quot;">​</a></h2><h3 id="筛选项" tabindex="-1">筛选项 <a class="header-anchor" href="#筛选项" aria-label="Permalink to &quot;筛选项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>模板名称</strong></td><td>占位：请输入模板名称。</td></tr><tr><td><strong>渠道类型</strong></td><td>全部 / 邮件 / QQ / 企业微信 / 钉钉 / Webhook / 短信。</td></tr><tr><td><strong>显示格式</strong></td><td>全部 / 文本 / 表格。</td></tr><tr><td><strong>启用状态</strong></td><td>全部 / 启用 / 禁用。</td></tr></tbody></table><p><strong>查询</strong> 刷新列表，<strong>重置</strong> 清空条件。</p><h3 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>新增模板</strong></td><td>打开「新增预警模板」弹窗。</td></tr><tr><td><strong>删除</strong></td><td><strong>批量删除</strong>：先勾选表格左侧 <strong>一条或多条</strong> 记录，再点删除，确认后逐条调用删除接口。未勾选时会提示先选择。</td></tr></tbody></table><h3 id="表格列" tabindex="-1">表格列 <a class="header-anchor" href="#表格列" aria-label="Permalink to &quot;表格列&quot;">​</a></h3><p>包含 <strong>模板名称</strong>、<strong>渠道类型</strong>（未选渠道时列表中显示为 <strong>通用</strong>）、<strong>显示格式</strong>（文本 / 表格标签样式）、<strong>启用状态</strong>（行内开关）、<strong>模板描述</strong>、创建与修改时间及操作人等。</p><h3 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h3><p><img src="'+d+'" alt="模板行右键菜单"></p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>查看详情</strong></td><td>打开只读弹窗，标题为 <strong>查看预警模板</strong>。</td></tr><tr><td><strong>编辑</strong></td><td>拉取详情后打开 <strong>编辑预警模板</strong>。</td></tr><tr><td><strong>删除</strong></td><td>删除当前行对应模板（确认后执行）。</td></tr></tbody></table><p>表格若还提供 <strong>复制行数据</strong> 等项，为通用表格能力。</p><hr><h2 id="新增-编辑-查看弹窗" tabindex="-1">新增 / 编辑 / 查看弹窗 <a class="header-anchor" href="#新增-编辑-查看弹窗" aria-label="Permalink to &quot;新增 / 编辑 / 查看弹窗&quot;">​</a></h2><p>标题：<strong>新增预警模板</strong>、<strong>编辑预警模板</strong>、<strong>查看预警模板</strong>。查看模式下确认即关闭，不提交保存。</p><h3 id="tab-基本信息" tabindex="-1">Tab：基本信息 <a class="header-anchor" href="#tab-基本信息" aria-label="Permalink to &quot;Tab：基本信息&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>模板名称</strong></td><td>必填；仅英文字母、数字、下划线，最长 64 字符；作为模板主键，编辑保存时使用当前表单中的名称。</td></tr><tr><td><strong>渠道类型</strong></td><td>可选「通用(不限制)」或具体渠道；切换渠道且 <strong>标题/内容模板仍为空</strong> 时，会自动填入该渠道对应的默认标题与默认内容草稿（避免覆盖已编辑内容）。</td></tr><tr><td><strong>显示格式</strong></td><td>必填：<strong>文本</strong> 或 <strong>表格</strong>。</td></tr><tr><td><strong>启用状态</strong></td><td>开关；禁用后仍可在列表中看到，但 <strong>hub0080</strong> 绑定时应注意勿选已禁用模板。</td></tr><tr><td><strong>模板描述</strong></td><td>可选，约 500 字内（以字数统计为准）。</td></tr></tbody></table><h3 id="tab-模板内容" tabindex="-1">Tab：模板内容 <a class="header-anchor" href="#tab-模板内容" aria-label="Permalink to &quot;Tab：模板内容&quot;">​</a></h3><p><img src="'+e+'" alt="模板内容 Tab（邮件渠道示例）"></p><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td><strong>标题模板</strong></td><td>单行或多行纯文本编辑器（CodeMirror），支持 <span>{{title}}</span>、<span>{{tag.severity}}</span> 等占位符。</td></tr><tr><td><strong>内容模板</strong></td><td><strong>邮件</strong>：富文本工具栏，适合排版 HTML 邮件；<strong>非邮件</strong>：Markdown 代码编辑器。</td></tr><tr><td><strong>占位符说明</strong></td><td>界面内嵌表格列出常用占位符：<code>title</code>、<code>content</code>、<code>timestamp</code>、<code>timestamp_iso</code>、<code>tags</code>、<code>tag.&lt;键&gt;</code>、<code>extra.&lt;键&gt;</code>、<code>table</code> / <code>table.&lt;列&gt;</code> 等；规则为 <span>{{field}}</span> 形式，未匹配字段将 <strong>原样保留</strong>。</td></tr><tr><td><strong>附件配置(JSON)</strong></td><td>可选，用于邮件附件等扩展（JSON 编辑器）。</td></tr></tbody></table><h3 id="tab-其他信息" tabindex="-1">Tab：其他信息 <a class="header-anchor" href="#tab-其他信息" aria-label="Permalink to &quot;Tab：其他信息&quot;">​</a></h3><p>备注、创建/修改时间与操作人（多为只读）。</p><hr><h2 id="与预警渠道-hub0080-的配合" tabindex="-1">与预警渠道（hub0080）的配合 <a class="header-anchor" href="#与预警渠道-hub0080-的配合" aria-label="Permalink to &quot;与预警渠道（hub0080）的配合&quot;">​</a></h2><p>在 <strong>预警服务配置</strong> 的渠道表单中，<strong>默认模板名称</strong> 的「…」选择器会按当前渠道的 <strong>渠道类型</strong> 过滤本模块中的模板。请保证模板 <strong>渠道类型</strong> 与渠道一致，或为 <strong>通用</strong>，且模板处于 <strong>启用</strong> 状态，避免选不到或发送失败。</p><hr><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ol><li>先确定渠道（邮件 / 企微等），再建模板，便于使用正确的编辑器（HTML vs Markdown）。</li><li>重大变更前可 <strong>导出或复制</strong> 当前 HTML/Markdown 备份（手动全选复制即可）。</li><li>占位符大小写与后端约定一致，自定义字段优先走 <code>extra.*</code> 或 <code>table.*</code> 命名空间。</li><li>批量删除前确认无 <strong>hub0080</strong> 渠道仍引用这些模板名称。</li></ol>',38)])])}const q=r(g,[["render",h]]);export{m as __pageData,q as default};
